#include <stdio.h>
#include <stdlib.h>
#define MAXN 100005
#define MAXM 200005
typedef struct Edge {
    int v, w, next;
} Edge;
Edge edges[MAXM];
int head[MAXN], tot = 0;
void addEdge(int u, int v, int w) {
    edges[tot].v = v;
    edges[tot].w = w;
    edges[tot].next = head[u];
    head[u] = tot++;
}
int dist[MAXN], cost[MAXN];
void dfs(int u, int fa) {
    dist[u] = 0;
    for (int i = head[u]; i != -1; i = edges[i].next) {
        int v = edges[i].v;
        if (v == fa) continue;
        dfs(v, u);
        dist[u] = (dist[u] > dist[v] + edges[i].w) ? dist[u] : dist[v] + edges[i].w;
    }
    cost[u] = dist[u];
    for (int i = head[u]; i != -1; i = edges[i].next) {
        int v = edges[i].v;
        if (v == fa) continue;
        cost[u] = (cost[u] < cost[v]) ? cost[u] : cost[v];
    }
}
int main() {
    int T, N, u, v, w;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        for (int i = 1; i <= N; i++) head[i] = -1;
        tot = 0;
        for (int i = 1; i < N; i++) {
            scanf("%d %d %d", &u, &v, &w);
            addEdge(u, v, w);
            addEdge(v, u, w);
        }
        dfs(1, 0);
        for (int i = 1; i <= N; i++) printf("%d\n", cost[i]);
    }
    return 0;
}

