#include <iostream>
#include <vector>
using namespace std;
typedef pair<int, int> pii;
const int MAXN = 100005;
vector<pii> edges[MAXN];
int dist[MAXN], cost[MAXN];
void dfs(int u, int fa) {
    dist[u] = 0;
    for (auto &e : edges[u]) {
        int v = e.first;
        if (v == fa) continue;
        dfs(v, u);
        dist[u] = max(dist[u], dist[v] + e.second);
    }
    cost[u] = dist[u];
    for (auto &e : edges[u]) {
        int v = e.first;
        if (v == fa) continue;
        cost[u] = min(cost[u], cost[v]);
    }
}
int main() {
    int T, N, u, v, w;
    cin >> T;
    while (T--) {
        cin >> N;
        for (int i = 1; i <= N; i++) edges[i].clear();
        for (int i = 1; i < N; i++) {
            cin >> u >> v >> w;
            edges[u].push_back({v, w});
            edges[v].push_back({u, w});
        }
        dfs(1, 0);
        for (int i = 1; i <= N; i++) cout << cost[i] << endl;
    }
    return 0;
}

