import java.util.ArrayList;
import java.util.List;
import java.util.Scanner;
public class Main {
    static class Edge {
        int v, w;
        Edge(int v, int w) {
            this.v = v;
            this.w = w;
        }
    }
    static List<Edge>[] edges;
    static int[] dist, cost;
    public static void dfs(int u, int fa) {
        dist[u] = 0;
        for (Edge e : edges[u]) {
            int v = e.v;
            if (v == fa) continue;
            dfs(v, u);
            dist[u] = Math.max(dist[u], dist[v] + e.w);
        }
        cost[u] = dist[u];
        for (Edge e : edges[u]) {
            int v = e.v;
            if (v == fa) continue;
            cost[u] = Math.min(cost[u], cost[v]);
        }
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            edges = new List[N + 1];
            dist = new int[N + 1];
            cost = new int[N + 1];
            for (int i = 1; i <= N; i++) {
                edges[i] = new ArrayList<>();
            }
            for (int i = 1; i < N; i++) {
                int u = sc.nextInt();
                int v = sc.nextInt();
                int w = sc.nextInt();
                edges[u].add(new Edge(v, w));
                edges[v].add(new Edge(u, w));
            }
            dfs(1, 0);
            for (int i = 1; i <= N; i++) {
                System.out.println(cost[i]);
            }
        }
    }
}

