const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => input[idx++];
const MAXN = 100005;
let edges, dist, cost;
function dfs(u, fa) {
    dist[u] = 0;
    for (let [v, w] of edges[u]) {
        if (v === fa) continue;
        dfs(v, u);
        dist[u] = Math.max(dist[u], dist[v] + w);
    }
    cost[u] = dist[u];
    for (let [v, w] of edges[u]) {
        if (v === fa) continue;
        cost[u] = Math.min(cost[u], cost[v]);
    }
}
let T = parseInt(readline());
while (T-- > 0) {
    let N = parseInt(readline());
    edges = Array.from({ length: N + 1 }, () => []);
    dist = new Array(N + 1).fill(0);
    cost = new Array(N + 1).fill(0);
