        let [u, v, w] = readline().split(' ').map(Number);
        edges[u].push([v, w]);
        edges[v].push([u, w]);
    }
    dfs(1, 0);
    for (let i = 1; i <= N; i++) {
        console.log(cost[i]);
    }
